import React, { useState } from 'react'; 
import axios from 'axios'; 
const Search = () => { 
  const [keyword, setKeyword] = useState(''); 
  const [results, setResults] = useState([]); 
  const handleSearch = async () => { 
    try { 
      const res = await axios.get(`http://localhost:5000/api/songs/search?q=${keyword}`); 
      setResults(res.data); 
    } catch (err) { console.error(err); alert("Loi ket noi server!"); } 
  }; 
  return ( 
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}> 
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}> 
        <input style={{ flex: 1, padding: '10px', borderRadius: '20px', border: '1px solid #ddd' }}  
          type="text" placeholder="Tìm bài hát..." onChange={e => setKeyword(e.target.value)} /> 
        <button onClick={handleSearch} style={{ padding: '10px 20px', borderRadius: '20px', background: '#1db954', color: 'white', border: 'none', cursor: 'pointer' }}>Tìm</button> 
      </div> 
      <div> 
        {results.map(s => ( 
          <div key={s._id} style={{ display: 'flex', alignItems: 'center', padding: '10px', borderBottom: '1px solid #eee' }}> 
            <img src={`http://localhost:5000${s.imageUrl}`} style={{ width: '50px', height: '50px', marginRight: '15px' }} /> 
            <div><b>{s.title}</b><p>{s.artist}</p></div> 
          </div> 
        ))} 
      </div> 
    </div> 
  ); 
}; export default Search;
